#include<iostream>
#include<vector>
#include<queue>
#include<array>
#include<string>
#include<algorithm>
using namespace std;


int main(){
    int n,m;
    cin >> n >> m;
    vector<vector<array<int,3>>> par(n,{m,{0,0,0}});
    vector<vector<int>> map(n,vector<int>(m));
    for(auto& x:map){
        for(auto& y:x){
            cin >> y;
        }
    }
    bool ans = false;
    queue<array<int,2>> q;
    q.push({0,0});
    map[0][0] = 0;
    while(!q.empty()){
        auto [x,y] = q.front();
        q.pop();
        if(x == n-1 && y == m-1){
            ans = true;
            break;
        }
        if (x-1 >= 0 && map[x-1][y] == 1){
            map[x-1][y] = 0;
            par[x-1][y] = {x,y,1};
            q.push({x-1,y});
        }
        if (x+1 < n && map[x+1][y] == 1){
            map[x+1][y] = 0;
            par[x+1][y] = {x,y,2};
            q.push({x+1,y});
        }
        if (y-1 >= 0 && map[x][y-1] == 1){
            map[x][y-1] = 0;
            par[x][y-1] = {x,y,3};
            q.push({x,y-1});
        }
        if (y+1 < m && map[x][y+1] == 1){
            map[x][y+1] = 0;
            par[x][y+1] = {x,y,4};
            q.push({x,y+1});
        }
    }
    if(ans){
        string path = "";
        int x = n-1, y = m-1;
        while(x != 0 || y != 0){
            auto [px,py,d] = par[x][y];
            path += to_string(d);
            x = px;
            y = py;
        }
        reverse(path.begin(),path.end());
        cout << path << endl;
        cout << path.size() << endl;
    }else{
        cout << "Just Monika" << endl;
    }
}
